import React from "react"
import { graphql, useStaticQuery } from "gatsby"
import Layout from "../components/layout";

export default function Post() {
  const { allMarkdownRemark } = useStaticQuery(
    graphql`
      query {
        allMarkdownRemark {
          edges {
            node {
              frontmatter {
                date(
                  formatString: "DD MMMM YYYY"
                  locale: "fr-FR"
                )
                slug
                title
              }
              html
            }
          }
        }
      }
    `
  )

  return (
    <Layout>
      test
    </Layout>
  )
}
